w:r.w:t:
ipAddress = "192.168.0.33";
boardName = "Nano33IoT";

neutralPosition = 0.5;
amplitudePosition = 0.15;
frequencyHz = 0.25;
sampleTimeSeconds = 0.02;
durationSeconds = 10.0;

arduinoObj = arduino(ipAddress, boardName);

aileronLeft = servo(arduinoObj, "D9");
aileronRight = servo(arduinoObj, "D10");
rudder = servo(arduinoObj, "D11");
elevator = servo(arduinoObj, "D12");

servos = {aileronLeft, aileronRight, rudder, elevator};

% Move all servos to neutral before the sine-wave test.
for servoIndex = 1:numel(servos)
    writePosition(servos{servoIndex}, neutralPosition);
end

pause(1);

% Send the same sine-wave position command to all four servos.
timeVectorSeconds = 0:sampleTimeSeconds:durationSeconds;

for timeIndex = 1:numel(timeVectorSeconds)
    commandPosition = neutralPosition + amplitudePosition * sin(2 * pi * frequencyHz * timeVectorSeconds(timeIndex));
    commandPosition = min(max(commandPosition, 0), 1);

    for servoIndex = 1:numel(servos)
        writePosition(servos{servoIndex}, commandPosition);
    end

    pause(sampleTimeSeconds);
end

% Return to neutral at the end of the test.
for servoIndex = 1:numel(servos)
    writePosition(servos{servoIndex}, neutralPosition);
end

pause(1);
